{{ {{{|safesubst:}}}#invoke:Unsubst||date=__DATE__ |$B=
<!--{{Lead too short}} begin-->{{Ambox
| name  = Lead too short
| subst = <includeonly>{{subst:substcheck}}</includeonly>
| type  = content
| image = [[File:Wiki letter w.svg|40px]]
| class = ambox-lead_too_short
| issue = This article's [[Wikipedia:Manual of Style/Lead section#Length|lead section]] '''may be too short to adequately [[Wikipedia:summary style|summarize]] the key points'''. 
| fix = Please consider expanding the lead to [[Wikipedia:Manual of Style/Lead section#Provide an accessible overview|provide an accessible overview]] of all important aspects of the article. {{#if:{{{reason|}}}|The reason given is: '''{{{reason}}}'''}}
| cat   = Wikipedia introduction cleanup
| all   = All pages needing cleanup
| cat2  = Articles covered by WikiProject Wikify
| all2  = All articles covered by WikiProject Wikify
| date  = {{{date|}}}
| talk = {{{talk|}}}
}}<!--{{Lead too short}} end-->
}}<noinclude>
{{Documentation}}
<!-- Add categories to the /doc subpage and interwikis in Wikidata, not here! -->
</noinclude>

